    'faculty.role7': 'Associate Professor',
    'faculty.bio7': 'Candidate of Technical Sciences, Associate Professor. Teaches «Intellectual and Industrial Property», combining legal aspects of protecting developments with practical food technology tasks.',
    'faculty.name8': 'Yurii V. Buhii',
    'faculty.role8': 'Associate Professor',
    'faculty.bio8': 'Candidate of Technical Sciences, Associate Professor. Specialises in innovative winemaking and spirit fermentation technologies; participates in developing modern technological solutions for the industry.',
    'faculty.name9': 'Roman H. Kyrylenko',
    'faculty.role9': 'Associate Professor',
    'faculty.bio9': 'Candidate of Technical Sciences, Associate Professor at the Department of BPBV. Involved in student training and research in fermentation product technologies.',
    'faculty.name10': 'Svitlana I. Oliinyk',
    'faculty.role10': 'Associate Professor, Department Secretary',
    'faculty.bio10': 'Candidate of Technical Sciences, Associate Professor. Secretary of the Department of BPBV; responsible for organisation of the teaching process and department paperwork.',
    'faculty.name11': 'Zoriana M. Romanova',
    'faculty.role11': 'Associate Professor',
    'faculty.bio11': 'Candidate of Technical Sciences, Associate Professor at the Department of BPBV. Involves students in research topics related to biotechnology of fermentation products.',
    'faculty.name12': 'Liudmyla V. Bondarenko',
    'faculty.role12': 'Laboratory Manager',
    'faculty.bio12': 'Laboratory Manager at the Department of BPBV. Ensures the operation of teaching and research laboratories; responsible for modern equipment and support of the department\'s experimental base.',
    'faculty.consultationScheduleTitle': 'Faculty consultation schedule (Semester I 2025–2026)',
